31	export default function HabitsPage() {
32	  const [habits, setHabits] = useState<Habit[]>([]);
33	  const [loading, setLoading] = useState(true);
34	  const [showForm, setShowForm] = useState(false);
35	  const [editId, setEditId] = useState<string | null>(null);
36	  const [form, setForm] = useState({
37	    title: "", description: "", domainIdx: 0, unit: "次",
38	    targetValue: 1, frequency: "daily",
39	  });
40	
41	  // Domain management state
42	  const [showDomainManager, setShowDomainManager] = useState(false);
43	  const [domainManagerView, setDomainManagerView] = useState<"list" | "new" | "edit">("list");
44	  const [domainForm, setDomainForm] = useState<Domain>({ name: "", icon: "dumbbell", color: "#ef4444" });
45	  const [editingDomainName, setEditingDomainName] = useState<string | null>(null);
46	  const [saving, setSaving] = useState(false);
47	
48	  useDidShow(() => { fetchHabits(); });
49	
50	  async function fetchHabits() {
51	    try {
52	      setHabits(await apiFetch("/api/habits"));
53	    } catch (e: any) {
54	      console.error("[fetchHabits]", e);
55	      showToast({ title: "获取习惯列表失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
56	    }
57	    setLoading(false);
58	  }
59	
60	  function openNew() {
61	    setEditId(null);
62	    setForm({ title: "", description: "", domainIdx: 0, unit: "次", targetValue: 1, frequency: "daily" });
63	    setShowForm(true);
64	  }
65	
66	  function openEdit(h: Habit) {
67	    setEditId(h.id);
68	    const domains = getDomains();
69	    const idx = domains.findIndex(d => d.name === h.domainId);
70	    setForm({
71	      title: h.title,
72	      description: h.description || "",
73	      domainIdx: idx >= 0 ? idx : domains.length - 1,
74	      unit: h.unit,
75	      targetValue: h.targetValue,
76	      frequency: h.frequency,
77	    });
78	    setShowForm(true);
79	  }
80	
81	  async function handleSave() {
82	    const domains = getDomains();
83	    if (form.domainIdx < 0 || form.domainIdx >= domains.length) {
84	      showToast({ title: "领域索引无效", icon: "none" });
85	      return;
86	    }
87	    setSaving(true);
88	    try {
89	      const body = { ...form, domainId: domains[form.domainIdx].name };
90	      if (editId) {
91	        await apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id: editId, ...body }) });
92	      } else {
93	        await apiFetch("/api/habits", { method: "POST", body: JSON.stringify(body) });
94	      }
95	      setShowForm(false);
96	      fetchHabits();
97	    } catch (e: any) {
98	      console.error("[handleSave]", e);
99	      showToast({ title: "保存习惯失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
100	    } finally {
101	      setSaving(false);
102	    }
103	  }
104	
105	  async function deleteHabit(id: string) {
106	    try {
107	      await apiFetch("/api/habits", { method: "DELETE", body: JSON.stringify({ id }) });
108	      fetchHabits();
109	    } catch (e: any) {
110	      console.error("[deleteHabit]", e);
111	      showToast({ title: "删除习惯失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
112	    }
113	  }
114	
115	  async function toggleActive(id: string, current: boolean) {
116	    try {
117	      await apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id, isActive: !current }) });
118	      fetchHabits();
119	    } catch (e: any) {
120	      console.error("[toggleActive]", e);
121	      showToast({ title: "操作失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
122	    }
123	  }
124	
125	  // ---- Domain management handlers ----
126	
127	  function openDomainManager() {
128	    setShowForm(false);
129	    setDomainManagerView("list");
130	    setDomainForm({ name: "", icon: "dumbbell", color: "#ef4444" });
131	    setEditingDomainName(null);
132	    setShowDomainManager(true);
133	  }
134	
135	  function openNewDomain() {
136	    setDomainForm({ name: "", icon: "dumbbell", color: "#ef4444" });
137	    setDomainManagerView("new");
138	  }
139	
140	  function openEditDomain(domain: Domain) {
141	    setEditingDomainName(domain.name);
142	    setDomainForm({ name: domain.name, icon: domain.icon, color: domain.color });
143	    setDomainManagerView("edit");
144	  }
145	
146	  async function handleDomainSave() {
147	    const name = domainForm.name.trim();
148	    if (!name) return;
149	
150	    const userDomains = getDomains().filter(d => d.name !== UNCATEGORIZED.name);
151	
152	    if (domainManagerView === "new") {
153	      if (userDomains.some(d => d.name === name)) {
154	        showModal({ title: "提示", content: "该领域名称已存在", showCancel: false });
155	        return;
156	      }
157	      userDomains.push({ name, icon: domainForm.icon, color: domainForm.color });
158	    } else if (domainManagerView === "edit") {
159	      const idx = userDomains.findIndex(d => d.name === editingDomainName);
160	      if (idx === -1) return;
161	
162	      if (name !== editingDomainName && userDomains.some(d => d.name === name)) {
163	        showModal({ title: "提示", content: "该领域名称已存在", showCancel: false });
164	        return;
165	      }
166	
167	      const oldName = userDomains[idx].name;
168	      userDomains[idx] = { name, icon: domainForm.icon, color: domainForm.color };
169	
170	      // If domain renamed, update all habits under old name
171	      if (name !== oldName) {
172	        try {
173	          await Promise.all(habits.filter(h => h.domainId === oldName).map(h =>
174	            apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id: h.id, domainId: name }) })
175	          ));
176	          fetchHabits();
177	        } catch (e: any) {
178	          console.error("[handleDomainSave-migrate]", e);
179	          showToast({ title: "迁移习惯失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
180	          return;
181	        }
182	      }
183	    }
184	
185	    saveDomains(userDomains);
186	    setDomainManagerView("list");
187	    setEditingDomainName(null);
188	  }
189	
190	  async function handleDeleteDomain(domain: Domain) {
191	    const count = habits.filter(h => h.domainId === domain.name).length;
192	    const res = await showModal({
193	      title: "删除领域",
194	      content: `确定删除"${domain.name}"吗？其下 ${count} 个习惯将移入"未分类"。`,
195	    });
196	
197	    if (!res.confirm) return;
198	
199	    setSaving(true);
200	    try {
201	      // Move habits to 未分类 first, then delete domain
202	      await Promise.all(habits.filter(h => h.domainId === domain.name).map(h =>
203	        apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id: h.id, domainId: UNCATEGORIZED.name }) })
204	      ));
205	
206	      const userDomains = getDomains()
207	        .filter(d => d.name !== UNCATEGORIZED.name && d.name !== domain.name);
208	      saveDomains(userDomains);
209	
210	      fetchHabits();
211	    } catch (e: any) {
212	      console.error("[handleDeleteDomain]", e);
213	      showToast({ title: "删除领域失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
214	    } finally {
215	      setSaving(false);
216	    }
217	  }
218	
219	  const domains = getDomains();
220	
221	  return (
222	    <View className="page">
223	      <View className="page-header">
224	        <View>
225	          <Text className="page-title">习惯管理</Text>
226	          <Text className="page-subtitle">管理你的每日修炼清单</Text>
227	        </View>
228	        <View className="add-btn" onClick={openNew}><Text>+</Text></View>
229	      </View>
230	
231	      {domains.map((domain) => {
232	        const domainHabits = habits.filter((h) => h.domainId === domain.name);
233	        return (
234	          <View key={domain.name}>
235	            <View className="domain-title-row">
236	              <Icon name={domain.icon as IconName} size={36} color="accent" />
237	              <Text className="domain-title">{domain.name}</Text>
238	            </View>
239	            {domainHabits.map((habit) => (
240	              <View key={habit.id} className={`habit-card ${!habit.isActive ? "inactive" : ""}`}>
241	                <View className="habit-info">
242	                  <Text className="habit-name">{habit.title}</Text>
243	                  {habit.description && <Text className="habit-desc">{habit.description}</Text>}
244	                  <View className="habit-meta">
245	                    <Text>{habit.frequency === "daily" ? "每日" : habit.frequency}</Text>
246	                    <Text> · </Text>
247	                    <Text>目标 {habit.targetValue}{habit.unit}</Text>
248	                  </View>
249	                </View>
250	                <View className="habit-actions">
251	                  <Text className={`action-btn ${saving ? "disabled" : ""}`} onClick={() => !saving && toggleActive(habit.id, habit.isActive)}>
252	                    {habit.isActive ? "停用" : "启用"}
253	                  </Text>
254	                  <Text className="action-btn" onClick={() => openEdit(habit)}>编辑</Text>
255	                  <Text className={`action-btn danger ${saving ? "disabled" : ""}`} onClick={() => !saving && deleteHabit(habit.id)}>删除</Text>
256	                </View>
257	              </View>
258	            ))}
259	          </View>
260	        );
261	      })}
262	
263	      <View className="domain-manager-entry" onClick={openDomainManager}>
264	        <View className="domain-manager-entry-bar" />
265	        <Text className="domain-manager-entry-text">管理分类</Text>
266	        <Text className="domain-manager-entry-arrow">&#8250;</Text>
267	      </View>
268	
269	      {!loading && habits.length === 0 && (
270	        <View className="empty"><Text>还没有习惯，点右上角 + 开始</Text></View>
271	      )}
272	
273	      {/* ---- Habit Form Modal ---- */}
274	      {showForm && (
275	        <View className="modal-mask" onClick={() => setShowForm(false)}>
276	          <View className="modal" onClick={(e) => e.stopPropagation()}>
277	            <Text className="modal-title">{editId ? "编辑习惯" : "新增习惯"}</Text>
278	
279	            <View className="form-group">
280	              <Text className="form-label">名称</Text>
281	              <Input className="form-input" placeholder="如：晨跑30分钟" value={form.title} onInput={(e) => setForm({ ...form, title: e.detail.value })} />
282	            </View>
283	
284	            <View className="form-group">
285	              <Text className="form-label">描述</Text>
286	              <Input className="form-input" placeholder="具体怎么做" value={form.description} onInput={(e) => setForm({ ...form, description: e.detail.value })} />
287	            </View>
288	
289	            <View className="form-row">
290	              <View className="form-group flex-1">
291	                <Text className="form-label">领域</Text>
292	                <Picker mode="selector" range={domains.map(d => d.name)} value={form.domainIdx} onChange={(e) => setForm({ ...form, domainIdx: +e.detail.value })}>
293	                  <View className="form-picker">
294	                    <Icon name={domains[form.domainIdx].icon as IconName} size={32} color="accent" />
295	                    <Text> {domains[form.domainIdx].name}</Text>
296	                  </View>
297	                </Picker>
298	              </View>
299	              <View className="form-group flex-1">
300	                <Text className="form-label">频率</Text>
301	                <Picker mode="selector" range={["每日", "每周", "工作日"]} value={form.frequency === "daily" ? 0 : form.frequency === "weekly" ? 1 : 2} onChange={(e) => setForm({ ...form, frequency: ["daily", "weekly", "weekday"][+e.detail.value] })}>
302	                  <View className="form-picker">{form.frequency === "daily" ? "每日" : form.frequency === "weekly" ? "每周" : "工作日"}</View>
303	                </Picker>
304	              </View>
305	            </View>
306	
307	            <View className="form-row">
308	              <View className="form-group flex-1">
309	                <Text className="form-label">目标值</Text>
310	                <Input className="form-input" type="number" value={String(form.targetValue)} onInput={(e) => setForm({ ...form, targetValue: +e.detail.value || 1 })} />
311	              </View>
312	              <View className="form-group flex-1">
313	                <Text className="form-label">单位</Text>
314	                <Input className="form-input" placeholder="次/分钟/页" value={form.unit} onInput={(e) => setForm({ ...form, unit: e.detail.value })} />
315	              </View>
316	            </View>
317	
318	            <View className="form-buttons">
319	              <View className="btn-cancel" onClick={() => setShowForm(false)}><Text>取消</Text></View>
320	              <View className={"btn-save" + (saving ? " disabled" : "")} onClick={() => !saving && handleSave()}><Text>{editId ? "保存" : "添加"}</Text></View>
321	            </View>
322	          </View>
323	        </View>
324	      )}
325	
326	      {/* ---- Domain Manager Modal ---- */}
327	      {showDomainManager && (
328	        <View className="modal-mask" onClick={() => setShowDomainManager(false)}>
329	          <View className="modal" onClick={(e) => e.stopPropagation()}>
330	            <View className="domain-manager-accent" />
331	
332	            {/* List View */}
333	            {domainManagerView === "list" && (
334	              <>
335	                <View className="modal-header-row">
336	                  <Text className="modal-title">管理分类</Text>
337	                  <Text className="modal-add-btn" onClick={openNewDomain}>+ 新增</Text>
338	                </View>
339	
340	                {domains.map((domain) => {
341	                  const isSystem = domain.name === UNCATEGORIZED.name;
342	                  return (
343	                    <View key={domain.name} className="domain-item">
344	                      <View className="domain-item-bar" style={{ backgroundColor: domain.color }} />
345	                      <View className="domain-item-icon">
346	                        <Icon name={domain.icon as IconName} size={36} color="accent" />
347	                      </View>
348	                      <Text className="domain-item-name">{domain.name}</Text>
349	                      {isSystem ? (
350	                        <Text className="domain-item-tag">系统</Text>
351	                      ) : (
352	                        <View className="domain-item-actions">
353	                          <View className="domain-item-action edit" onClick={() => openEditDomain(domain)}>
354	                            <Text>&#9998;</Text>
355	                          </View>
356	                          <View className={`domain-item-action delete${saving ? " disabled" : ""}`} onClick={() => !saving && handleDeleteDomain(domain)}>
357	                            <Text>&#10005;</Text>
358	                          </View>
359	                        </View>
360	                      )}
361	                    </View>
362	                  );
363	                })}
364	
365	                <View className="domain-close-btn" onClick={() => setShowDomainManager(false)}>
366	                  <Text>关闭</Text>
367	                </View>
368	              </>
369	            )}
370	
371	            {/* New / Edit Form View */}
372	            {(domainManagerView === "new" || domainManagerView === "edit") && (
373	              <>
374	                <Text className="modal-title">{domainManagerView === "new" ? "新增分类" : "编辑分类"}</Text>
375	
376	                <View className="form-group">
377	                  <Text className="form-label">名称</Text>
378	                  <Input
379	                    className="form-input"
380	                    placeholder="分类名称"
381	                    value={domainForm.name}
382	                    onInput={(e) => setDomainForm({ ...domainForm, name: e.detail.value })}
383	                  />
384	                </View>
385	
386	                <View className="form-section">
387	                  <Text className="form-section-title">图标</Text>
388	                  <View className="icon-picker-grid">
389	                    {DOMAIN_ICON_OPTIONS.map((iconName) => (
390	                      <View
391	                        key={iconName}
392	                        className={`icon-pill ${domainForm.icon === iconName ? "selected" : ""}`}
393	                        onClick={() => setDomainForm({ ...domainForm, icon: iconName })}
394	                      >
395	                        <Icon name={iconName} size={56} color="primary" />
396	                      </View>
397	                    ))}
398	                  </View>
399	                </View>
400	
401	                <View className="form-section">
402	                  <Text className="form-section-title">颜色</Text>
403	                  <View className="color-picker-grid">
404	                    {COLOR_OPTIONS.map((color) => (
405	                      <View
406	                        key={color}
407	                        className={`color-swatch ${domainForm.color === color ? "selected" : ""}`}
408	                        onClick={() => setDomainForm({ ...domainForm, color })}
409	                      >
410	                        <View className="color-swatch-inner" style={{ backgroundColor: color }} />
411	                      </View>
412	                    ))}
413	                  </View>
414	                </View>
415	
416	                <View className="form-buttons">
417	                  <View className="btn-cancel" onClick={() => setDomainManagerView("list")}><Text>取消</Text></View>
418	                  <View className={"btn-save" + (saving ? " disabled" : "")} onClick={() => !saving && handleDomainSave()}><Text>保存</Text></View>
419	                </View>
420	              </>
421	            )}
422	
423	          </View>
424	        </View>
425	      )}
426	    </View>
427	  );
428	}
